4	import type { Element } from '@bim-ai/core';
5	
6	import { makeStairVolumeMesh } from './meshBuilders';
7	
8	type StairElem = Extract<Element, { kind: 'stair' }>;
9	type LevelElem = Extract<Element, { kind: 'level' }>;
10	
11	// Three levels at 0m, 3m, 6m forming a 3-storey stairwell.
12	const lvl0: LevelElem = { kind: 'level', id: 'lvl-0', name: 'L0', elevationMm: 0 };
13	const lvl1: LevelElem = { kind: 'level', id: 'lvl-1', name: 'L1', elevationMm: 3000 };
14	const lvl2: LevelElem = { kind: 'level', id: 'lvl-2', name: 'L2', elevationMm: 6000 };
15	
16	const threeStoreyElements: Record<string, Element> = {
17	  'lvl-0': lvl0,
18	  'lvl-1': lvl1,
19	  'lvl-2': lvl2,
20	};
21	
22	// Same stair without the intermediate level — single-storey equivalent spanning 6m.
23	const twoStoreyElements: Record<string, Element> = {
24	  'lvl-0': lvl0,
25	  'lvl-2': lvl2,
26	};
27	
28	const multiStoreyStair: StairElem = {
29	  kind: 'stair',
30	  id: 'stair-multi',
31	  name: 'Multi-Storey Stair',
32	  baseLevelId: 'lvl-0',
33	  topLevelId: 'lvl-2',
34	  runStartMm: { xMm: 0, yMm: 0 },
35	  runEndMm: { xMm: 5000, yMm: 0 },
36	  widthMm: 1200,
37	  riserMm: 175,
38	  treadMm: 250,
39	  multiStorey: true,
40	  runs: [
41	    {
42	      id: 'run-1',
43	      startMm: { xMm: 0, yMm: 0 },
44	      endMm: { xMm: 5000, yMm: 0 },
45	      widthMm: 1200,
46	      riserCount: 17,
47	    },
48	  ],
49	  landings: [],
50	};
51	
52	describe('WP-C C2 — multi-storey stair mesh', () => {
53	  it('3-storey stair (2 floor segments) has more mesh children than 1-segment equivalent', () => {
54	    const threeStoreyGroup = makeStairVolumeMesh(multiStoreyStair, threeStoreyElements, null);
55	    const singleStoreyGroup = makeStairVolumeMesh(
56	      { ...multiStoreyStair, multiStorey: false },
57	      twoStoreyElements,
58	      null,
59	    );
60	    // 3-storey stacks geometry for 2 floor segments (lvl-0→lvl-1, lvl-1→lvl-2),
61	    // while the single-storey renders only 1 segment.
62	    expect(threeStoreyGroup.children.length).toBeGreaterThan(singleStoreyGroup.children.length);
63	  });
64	
65	  it('bounding box max Y reaches approximately the top level elevation (6.0 m)', () => {
66	    const group = makeStairVolumeMesh(multiStoreyStair, threeStoreyElements, null);
67	    group.updateMatrixWorld(true);
68	    const box = new THREE.Box3().setFromObject(group);
69	    // Top of the highest tread should be at or very near 6.0 m.
70	    expect(box.max.y).toBeCloseTo(6.0, 1);
71	  });
72	});
