1	import { type JSX, useCallback, useEffect, useMemo, useRef, useState } from 'react';
2	
3	import type { Element } from '@bim-ai/core';
4	
5	type PhaseEl = Extract<Element, { kind: 'phase' }>;
6	
7	type CommandDispatcher = (cmd: Record<string, unknown>) => void | Promise<void>;
8	
9	interface PhaseRow {
10	  id: string;
11	  name: string;
12	  ord: number;
13	  description: string;
14	  elementCount: number;
15	}
16	
17	function countElementsInPhase(elementsById: Record<string, Element>, phaseId: string): number {
18	  return Object.values(elementsById).filter(
19	    (e) => (e as { phaseId?: string | null }).phaseId === phaseId,
20	  ).length;
21	}
22	
23	export function PhaseManagerDialog({
24	  open,
25	  onClose,
26	  elementsById,
27	  onSemanticCommand,
28	}: {
29	  open: boolean;
30	  onClose: () => void;
31	  elementsById: Record<string, Element>;
32	  onSemanticCommand: CommandDispatcher;
33	}): JSX.Element | null {
34	  const dialogRef = useRef<HTMLDivElement | null>(null);
35	
36	  const phases = useMemo(() => {
37	    const all = Object.values(elementsById) as Element[];
38	    return (all.filter((e) => e.kind === 'phase') as PhaseEl[])
39	      .sort((a, b) => a.ord - b.ord)
40	      .map(
41	        (p): PhaseRow => ({
42	          id: p.id,
43	          name: p.name,
44	          ord: p.ord,
45	          description: p.description ?? '',
46	          elementCount: countElementsInPhase(elementsById, p.id),
47	        }),
48	      );
49	  }, [elementsById]);
50	
51	  const [editingId, setEditingId] = useState<string | null>(null);
52	  const [editName, setEditName] = useState('');
53	  const [editDesc, setEditDesc] = useState('');
54	  const [newName, setNewName] = useState('');
55	  const [busy, setBusy] = useState(false);
56	  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);
57	  const [error, setError] = useState<string | null>(null);
58	
59	  useEffect(() => {
60	    if (!open) {
61	      setEditingId(null);
62	      setNewName('');
63	      setConfirmDeleteId(null);
64	      setError(null);
65	    }
66	  }, [open]);
67	
68	  useEffect(() => {
69	    if (open) dialogRef.current?.focus();
70	  }, [open]);
71	
72	  useEffect(() => {
73	    if (!open) return;
74	    const handler = (e: KeyboardEvent) => {
75	      if (e.key === 'Escape') onClose();
76	    };
77	    window.addEventListener('keydown', handler);
78	    return () => window.removeEventListener('keydown', handler);
79	  }, [open, onClose]);
80	
81	  const run = useCallback(
82	    async (cmds: Record<string, unknown>[]) => {
83	      setBusy(true);
84	      setError(null);
85	      try {
86	        for (const cmd of cmds) await onSemanticCommand(cmd);
87	      } catch {
88	        setError('Command failed.');
89	      } finally {
90	        setBusy(false);
91	      }
92	    },
93	    [onSemanticCommand],
94	  );
95	
96	  const startEdit = (row: PhaseRow) => {
97	    setEditingId(row.id);
98	    setEditName(row.name);
99	    setEditDesc(row.description);
100	  };
101	
102	  const commitEdit = async () => {
103	    if (!editingId) return;
104	    const row = phases.find((p) => p.id === editingId);
105	    if (!row) return;
106	    const cmds: Record<string, unknown>[] = [];
107	    if (editName.trim() && editName.trim() !== row.name) {
108	      cmds.push({
109	        type: 'updateElementProperty',
110	        elementId: editingId,
111	        key: 'name',
112	        value: editName.trim(),
113	      });
114	    }
115	    if (editDesc !== row.description) {
116	      cmds.push({
117	        type: 'updateElementProperty',
118	        elementId: editingId,
119	        key: 'description',
120	        value: editDesc,
121	      });
122	    }
123	    setEditingId(null);
124	    if (cmds.length) await run(cmds);
125	  };
126	
127	  const addPhase = async () => {
128	    const name = newName.trim();
129	    if (!name) return;
130	    const maxOrd = phases.reduce((m, p) => Math.max(m, p.ord), -1);
131	    const id = `phase-${name
132	      .toLowerCase()
133	      .replace(/[^a-z0-9]+/g, '-')
134	      .replace(/^-+|-+$/g, '')
135	      .slice(0, 32)}-${Date.now().toString(36)}`;
136	    setNewName('');
137	    await run([{ type: 'createPhase', id, name, ord: maxOrd + 1 }]);
138	  };
139	
140	  const deletePhase = async (row: PhaseRow) => {
141	    setConfirmDeleteId(null);
142	    await run([{ type: 'deleteElement', elementId: row.id }]);
143	  };
144	
145	  const movePhase = async (row: PhaseRow, direction: 'up' | 'down') => {
146	    const idx = phases.indexOf(row);
147	    const swapIdx = direction === 'up' ? idx - 1 : idx + 1;
148	    if (swapIdx < 0 || swapIdx >= phases.length) return;
149	    const other = phases[swapIdx];
150	    await run([
151	      { type: 'updateElementProperty', elementId: row.id, key: 'ord', value: String(other.ord) },
152	      { type: 'updateElementProperty', elementId: other.id, key: 'ord', value: String(row.ord) },
153	    ]);
154	  };
155	
156	  if (!open) return null;
157	
158	  const confirmRow = confirmDeleteId ? phases.find((p) => p.id === confirmDeleteId) : null;
159	
160	  return (
161	    <div
162	      role="dialog"
163	      aria-modal="true"
164	      aria-label="Manage Phases"
165	      style={{
166	        position: 'fixed',
167	        inset: 0,
168	        zIndex: 200,
169	        display: 'flex',
170	        alignItems: 'center',
171	        justifyContent: 'center',
172	        background: 'rgba(0,0,0,0.4)',
173	      }}
174	      onMouseDown={(e) => {
175	        if (e.target === e.currentTarget) onClose();
176	      }}
177	    >
178	      <div
179	        ref={dialogRef}
180	        tabIndex={-1}
181	        style={{
182	          background: 'var(--color-surface)',
183	          border: '1px solid var(--color-border)',
184	          borderRadius: 6,
185	          boxShadow: '0 4px 24px rgba(0,0,0,0.2)',
186	          width: 640,
187	          maxHeight: '80vh',
188	          display: 'flex',
189	          flexDirection: 'column',
190	          overflow: 'hidden',
191	          outline: 'none',
192	        }}
193	        onMouseDown={(e) => e.stopPropagation()}
194	      >
195	        {/* Header */}
196	        <div
197	          style={{
198	            display: 'flex',
199	            alignItems: 'center',
200	            justifyContent: 'space-between',
201	            padding: '12px 16px',
202	            borderBottom: '1px solid var(--color-border)',
203	            flexShrink: 0,
204	          }}
205	        >
206	          <span style={{ fontWeight: 600, fontSize: 14 }}>Manage Phases</span>
207	          <button
208	            onClick={onClose}
209	            aria-label="Close"
210	            style={{
211	              background: 'none',
212	              border: 'none',
213	              cursor: 'pointer',
214	              fontSize: 16,
215	              color: 'var(--color-text-secondary)',
216	              padding: '2px 6px',
217	            }}
218	          >
219	            ×
220	          </button>
221	        </div>
222	
223	        {/* Table */}
224	        <div style={{ overflowY: 'auto', flex: 1 }}>
225	          <table
226	            data-testid="phase-manager-table"
227	            style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}
228	          >
229	            <thead>
230	              <tr style={{ background: 'var(--color-background)' }}>
231	                <th
232	                  scope="col"
233	                  style={{ padding: '6px 8px', textAlign: 'left', fontWeight: 600, width: 32 }}
234	                >
235	                  Seq
236	                </th>
237	                <th scope="col" style={{ padding: '6px 8px', textAlign: 'left', fontWeight: 600 }}>
238	                  Name
239	                </th>
240	                <th scope="col" style={{ padding: '6px 8px', textAlign: 'left', fontWeight: 600 }}>
241	                  Description
242	                </th>
243	                <th
244	                  scope="col"
245	                  style={{ padding: '6px 8px', textAlign: 'right', fontWeight: 600, width: 56 }}
246	                >
247	                  Elements
248	                </th>
249	                <th scope="col" style={{ padding: '6px 8px', width: 120 }} />
250	              </tr>
251	            </thead>
252	            <tbody>
253	              {phases.map((row, idx) => {
254	                const isEditing = editingId === row.id;
255	                return (
256	                  <tr
257	                    key={row.id}
258	                    data-testid={`phase-row-${row.id}`}
259	                    style={{ borderTop: '1px solid var(--color-border)' }}
260	                  >
261	                    <td
262	                      style={{
263	                        padding: '6px 8px',
264	                        color: 'var(--color-text-secondary)',
265	                        textAlign: 'center',
266	                      }}
267	                    >
268	                      {row.ord + 1}
269	                    </td>
270	                    <td style={{ padding: '6px 4px' }}>
271	                      {isEditing ? (
272	                        <input
273	                          autoFocus
274	                          data-testid="phase-edit-name"
275	                          value={editName}
276	                          onChange={(e) => setEditName(e.currentTarget.value)}
277	                          onKeyDown={(e) => {
278	                            if (e.key === 'Enter') void commitEdit();
279	                            if (e.key === 'Escape') setEditingId(null);
280	                          }}
281	                          style={{
282	                            width: '100%',
283	                            fontSize: 13,
284	                            border: '1px solid var(--color-border)',
285	                            borderRadius: 3,
286	                            padding: '2px 6px',
287	                            background: 'var(--color-surface)',
288	                            color: 'var(--color-text)',
289	                          }}
290	                        />
291	                      ) : (
292	                        <span
293	                          role="button"
294	                          tabIndex={0}
295	                          onClick={() => startEdit(row)}
296	                          onKeyDown={(e) => {
297	                            if (e.key === 'Enter' || e.key === ' ') startEdit(row);
298	                          }}
299	                          style={{
300	                            cursor: 'text',
301	                            display: 'block',
302	                            padding: '2px 6px',
303	                            borderRadius: 3,
304	                          }}
305	                          title="Click to rename"
306	                        >
307	                          {row.name}
308	                        </span>
309	                      )}
310	                    </td>
311	                    <td style={{ padding: '6px 4px' }}>
312	                      {isEditing ? (
313	                        <input
314	                          data-testid="phase-edit-description"
315	                          value={editDesc}
316	                          onChange={(e) => setEditDesc(e.currentTarget.value)}
317	                          onKeyDown={(e) => {
318	                            if (e.key === 'Enter') void commitEdit();
319	                            if (e.key === 'Escape') setEditingId(null);
320	                          }}
321	                          style={{
322	                            width: '100%',
323	                            fontSize: 13,
324	                            border: '1px solid var(--color-border)',
325	                            borderRadius: 3,
326	                            padding: '2px 6px',
327	                            background: 'var(--color-surface)',
328	                            color: 'var(--color-text)',
329	                          }}
330	                        />
331	                      ) : (
332	                        <span
333	                          style={{
334	                            display: 'block',
335	                            padding: '2px 6px',
336	                            color: row.description
337	                              ? 'var(--color-text)'
338	                              : 'var(--color-text-secondary)',
339	                          }}
340	                        >
341	                          {row.description || '—'}
342	                        </span>
343	                      )}
344	                    </td>
345	                    <td
346	                      style={{
347	                        padding: '6px 8px',
348	                        textAlign: 'right',
349	                        color: 'var(--color-text-secondary)',
350	                      }}
351	                    >
352	                      {row.elementCount}
353	                    </td>
354	                    <td style={{ padding: '6px 8px' }}>
355	                      <div
356	                        style={{
357	                          display: 'flex',
358	                          gap: 4,
359	                          justifyContent: 'flex-end',
360	                          alignItems: 'center',
361	                        }}
362	                      >
363	                        {isEditing ? (
364	                          <>
365	                            <button
366	                              data-testid="phase-save-btn"
367	                              disabled={busy}
368	                              onClick={() => void commitEdit()}
369	                              style={smallBtn}
370	                            >
371	                              Save
372	                            </button>
373	                            <button onClick={() => setEditingId(null)} style={smallBtn}>
374	                              Cancel
375	                            </button>
376	                          </>
377	                        ) : (
378	                          <>
379	                            <button
380	                              aria-label="Move up"
381	                              disabled={busy || idx === 0}
382	                              onClick={() => void movePhase(row, 'up')}
383	                              style={iconBtn}
384	                              title="Move up"
385	                            >
386	                              ↑
387	                            </button>
388	                            <button
