1	import { render, screen, fireEvent, waitFor } from '@testing-library/react';
2	import { describe, it, expect, vi } from 'vitest';
3	import { PhaseManagerDialog } from './PhaseManagerDialog';
4	import type { Element } from '@bim-ai/core';
5	
6	function makePhase(id: string, name: string, ord: number, description = ''): Element {
7	  return { kind: 'phase', id, name, ord, description } as Element;
8	}
9	
10	function makeWall(id: string, phaseId: string): Element {
11	  return { kind: 'wall', id, phaseId } as unknown as Element;
12	}
13	
14	const baseElements: Record<string, Element> = {
15	  'phase-existing': makePhase('phase-existing', 'Existing', 0, 'Bestand'),
16	  'phase-demo': makePhase('phase-demo', 'Demolition', 1),
17	  'phase-new': makePhase('phase-new', 'New Construction', 2),
18	};
19	
20	describe('PhaseManagerDialog', () => {
21	  it('renders phases in sequence order', () => {
22	    render(
23	      <PhaseManagerDialog
24	        open
25	        onClose={vi.fn()}
26	        elementsById={baseElements}
27	        onSemanticCommand={vi.fn()}
28	      />,
29	    );
30	    const rows = screen.getAllByTestId(/^phase-row-/);
31	    expect(rows).toHaveLength(3);
32	    expect(rows[0]).toHaveTextContent('Existing');
33	    expect(rows[1]).toHaveTextContent('Demolition');
34	    expect(rows[2]).toHaveTextContent('New Construction');
35	  });
36	
37	  it('shows element count per phase', () => {
38	    const elements: Record<string, Element> = {
39	      ...baseElements,
40	      wall1: makeWall('wall1', 'phase-existing'),
41	      wall2: makeWall('wall2', 'phase-existing'),
42	      wall3: makeWall('wall3', 'phase-new'),
