1	/**
2	 * FAM-10 — clipboard persistence layer.
3	 *
4	 * Two writes happen on every copy:
5	 *   - localStorage under `bim-ai:clipboard` — primary in-browser path
6	 *   - navigator.clipboard.writeText — best-effort cross-tab fallback
7	 *
8	 * Reads prefer localStorage; if that's empty (e.g. user pasted from a
9	 * different browser tab) we attempt navigator.clipboard.readText. Both
10	 * paths defensively handle missing APIs and storage quota errors so
11	 * the rest of the app never sees a clipboard exception.
12	 */
13	import { CLIPBOARD_STORAGE_KEY, parseClipboardPayload, type ClipboardPayload } from './payload';
14	
15	export function writeClipboard(payload: ClipboardPayload): void {
16	  const json = JSON.stringify(payload);
17	  try {
18	    localStorage.setItem(CLIPBOARD_STORAGE_KEY, json);
19	  } catch {
20	    // Quota exhausted, private mode, etc. — fall back to nav clipboard.
21	  }
22	  if (typeof navigator !== 'undefined' && navigator.clipboard?.writeText) {
23	    void navigator.clipboard.writeText(json).catch(() => {});
24	  }
25	}
26	
27	export function readClipboardSync(): ClipboardPayload | null {
28	  try {
29	    return parseClipboardPayload(localStorage.getItem(CLIPBOARD_STORAGE_KEY));
30	  } catch {
31	    return null;
32	  }
33	}
34	
35	/**
36	 * Async path used by the paste handler — falls back to
37	 * `navigator.clipboard.readText` when localStorage is empty so a user
38	 * who copied in tab A can paste in tab B.
39	 */
40	export async function readClipboard(): Promise<ClipboardPayload | null> {
41	  const sync = readClipboardSync();
42	  if (sync) return sync;
43	  if (typeof navigator !== 'undefined' && navigator.clipboard?.readText) {
44	    try {
45	      const text = await navigator.clipboard.readText();
46	      return parseClipboardPayload(text);
47	    } catch {
48	      return null;
49	    }
50	  }
51	  return null;
