/**
 * Clone the clipboard payload's elements onto each target level.
 *
 * For each target level the function:
 * 1. Assigns fresh element ids so no clash with originals.
 * 2. Sets `levelId` on each element to the target level.
 * 3. Offsets `zMm` by (targetElevation − sourceElevation).
 *
 * Source level elevation is inferred from the first element that carries
 * a `levelId` field; falls back to 0 when absent.
 */
export function copyToLevels(args: CopyToLevelsArgs): CopyToLevelsResult {
  const { payload, targetLevelIds, elementsById } = args;

  // Infer source level elevation.
  let sourceLevelElevationMm = 0;
  for (const el of payload.elements) {
    const obj = el as unknown as Record<string, unknown>;
    const lid = typeof obj['levelId'] === 'string' ? (obj['levelId'] as string) : undefined;
    if (lid && elementsById[lid]) {
      const lvl = elementsById[lid] as unknown as Record<string, unknown>;
      if (typeof lvl['elevationMm'] === 'number') {
        sourceLevelElevationMm = lvl['elevationMm'] as number;
      }
      break;
    }
  }

  let salt = 0;
  const elementsByLevel: LevelElementGroup[] = [];

  for (const targetLevelId of targetLevelIds) {
    const targetLevel = elementsById[targetLevelId] as unknown as
      | Record<string, unknown>
      | undefined;
    const targetElevationMm =
      targetLevel && typeof targetLevel['elevationMm'] === 'number'
        ? (targetLevel['elevationMm'] as number)
        : 0;
    const deltaZ = targetElevationMm - sourceLevelElevationMm;

    const elements: Element[] = payload.elements.map((el) => {
      const obj = el as unknown as Record<string, unknown>;
      const next: Record<string, unknown> = { ...obj };

      // Fresh id.
      next['id'] =
        typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function'
          ? crypto.randomUUID()
          : `paste-${Date.now()}-${salt++}`;

      // Rebind level.
      if ('levelId' in next) next['levelId'] = targetLevelId;

      // Offset z.
      if (typeof next['zMm'] === 'number') {
        next['zMm'] = (next['zMm'] as number) + deltaZ;
      }

      return next as Element;
    });

    elementsByLevel.push({ levelId: targetLevelId, elements });
  }

  return { elementsByLevel };
}

/**
 * Convenience wrapper: paste clipboard elements aligned to each target
 * level and return a single flat array ready to merge into elementsById.
 */
export function pasteAlignedToLevels(args: CopyToLevelsArgs): Element[] {
  const { elementsByLevel } = copyToLevels(args);
  return elementsByLevel.flatMap((g) => g.elements);
}

// ---------------------------------------------------------------------------
// Private helpers
// ---------------------------------------------------------------------------

function reassignElementId(el: Element, salt: number): Element {
  const obj = el as unknown as Record<string, unknown>;
  const oldId = typeof obj['id'] === 'string' ? (obj['id'] as string) : 'el';
  const fresh =
    typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function'
      ? crypto.randomUUID()
      : `${oldId}-paste-${Date.now()}-${salt}`;
  return { ...obj, id: fresh } as Element;
}

import { cleanup, fireEvent, render, screen, waitFor } from '@testing-library/react';
import { afterEach, describe, expect, it, vi } from 'vitest';

import type { Element } from '@bim-ai/core';

import { ProjectInfoDialog } from './ProjectInfoDialog';

afterEach(() => {
  cleanup();
});

function makeProjectSettings(overrides: Record<string, unknown> = {}): Element {
  return {
    kind: 'project_settings',
    id: 'project_settings',
    name: 'My Project',
    projectNumber: 'PRJ-001',
    clientName: 'ACME Corp',
    projectStatus: 'Active',
    authorName: 'Jane Doe',
    issueDate: '2026-01-15',
    checkDate: 'John Smith',
    projectDescription: 'A test project',
    projectAddress: '123 Main St',
    ...overrides,
  } as unknown as Element;
}

const baseElements: Record<string, Element> = {
  project_settings: makeProjectSettings(),
};

describe('ProjectInfoDialog', () => {
  it('returns null when closed', () => {
    const { container } = render(
      <ProjectInfoDialog
        open={false}
        onClose={vi.fn()}
        elementsById={baseElements}
        onSemanticCommand={vi.fn()}
      />,
    );
    expect(container.firstChild).toBeNull();
  });

  it('populates fields from project_settings on open', () => {
    render(
      <ProjectInfoDialog
        open
        onClose={vi.fn()}
        elementsById={baseElements}
        onSemanticCommand={vi.fn()}
      />,
    );
    expect((screen.getByTestId('project-info-name') as HTMLInputElement).value).toBe('My Project');
    expect((screen.getByTestId('project-info-number') as HTMLInputElement).value).toBe('PRJ-001');
    expect((screen.getByTestId('project-info-client') as HTMLInputElement).value).toBe('ACME Corp');
    expect((screen.getByTestId('project-info-author') as HTMLInputElement).value).toBe('Jane Doe');
    expect((screen.getByTestId('project-info-issuedate') as HTMLInputElement).value).toBe(
      '2026-01-15',
    );
  });

  it('dispatches updateElementProperty commands for each field on save', async () => {
    const dispatch = vi.fn();
    render(
      <ProjectInfoDialog
        open
        onClose={vi.fn()}
        elementsById={baseElements}
        onSemanticCommand={dispatch}
      />,
    );
    fireEvent.change(screen.getByTestId('project-info-name'), {
      target: { value: 'New Name' },
    });
    fireEvent.click(screen.getByTestId('project-info-save'));
    await waitFor(() => expect(dispatch).toHaveBeenCalled());
    const calls = dispatch.mock.calls.map((c) => c[0] as Record<string, unknown>);
    const nameCmd = calls.find((c) => c.key === 'name');
    expect(nameCmd).toBeDefined();
    expect(nameCmd?.type).toBe('updateElementProperty');
    expect(nameCmd?.value).toBe('New Name');
    expect(nameCmd?.elementId).toBe('project_settings');
  });

  it('closes on Escape key', () => {
    const onClose = vi.fn();
    render(
      <ProjectInfoDialog
        open
        onClose={onClose}
        elementsById={baseElements}
        onSemanticCommand={vi.fn()}
      />,
    );
    fireEvent.keyDown(window, { key: 'Escape' });
    expect(onClose).toHaveBeenCalledTimes(1);
  });

  it('works with empty elementsById (no project settings yet)', async () => {
    const dispatch = vi.fn();
    render(
      <ProjectInfoDialog open onClose={vi.fn()} elementsById={{}} onSemanticCommand={dispatch} />,
    );
    expect((screen.getByTestId('project-info-name') as HTMLInputElement).value).toBe('');
    fireEvent.change(screen.getByTestId('project-info-name'), { target: { value: 'Brand New' } });
    fireEvent.click(screen.getByTestId('project-info-save'));
    await waitFor(() => expect(dispatch).toHaveBeenCalled());
    const firstCmd = dispatch.mock.calls[0][0] as Record<string, unknown>;
    expect(firstCmd.type).toBe('upsertProjectSettings');
  });
});

